"""Camada de banco — Ferrari IoT."""

from datetime import datetime
import bcrypt
from sqlalchemy import create_engine
from sqlalchemy.orm import Session, sessionmaker
from config import settings
from models import ActionLog, Base, Device, TelemetrySample, User

engine = create_engine(settings.database_url, connect_args={"check_same_thread": False})
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

DEFAULT_DEVICES = [
    {"device_id": "arduino-ferrari", "name": "Arduino Ferrari Node", "kind": "arduino", "status": "online"},
    {"device_id": "raspberry-hub", "name": "Raspberry Pi Hub", "kind": "raspberry", "status": "online"},
    {"device_id": "door-driver", "name": "Porta Motorista", "kind": "door", "status": "closed"},
    {"device_id": "door-passenger", "name": "Porta Passageiro", "kind": "door", "status": "closed"},
    {"device_id": "roof", "name": "Teto Retrátil", "kind": "roof", "status": "closed"},
    {"device_id": "engine", "name": "Motor V8", "kind": "engine", "status": "off"},
    {"device_id": "sound", "name": "Sistema de Som", "kind": "sound", "status": "off"},
    {"device_id": "headlight", "name": "Faróis LED", "kind": "light", "status": "off"},
    {"device_id": "tracker", "name": "GPS Tracker", "kind": "gps", "status": "idle"},
    {"device_id": "alarm", "name": "Alarme", "kind": "alarm", "status": "armed"},
    {"device_id": "spoiler", "name": "Aerofólio Ativo", "kind": "spoiler", "status": "retracted"},
    {"device_id": "climate", "name": "Climatização", "kind": "climate", "status": "off"},
]

def hash_password(plain: str) -> str:
    return bcrypt.hashpw(plain.encode("utf-8"), bcrypt.gensalt()).decode("utf-8")

def verify_password(plain: str, hashed: str) -> bool:
    try:
        return bcrypt.checkpw(plain.encode("utf-8"), hashed.encode("utf-8"))
    except ValueError:
        return False

def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

def init_db() -> None:
    Base.metadata.create_all(bind=engine)
    db = SessionLocal()
    try:
        if not db.query(User).filter(User.username == settings.admin_user).first():
            db.add(User(username=settings.admin_user, password_hash=hash_password(settings.admin_password)))
        for item in DEFAULT_DEVICES:
            if not db.query(Device).filter(Device.device_id == item["device_id"]).first():
                db.add(Device(**item, last_seen=datetime.utcnow()))
        if db.query(TelemetrySample).count() == 0:
            db.add(TelemetrySample(rpm=800, speed_kmh=0, engine_temp=78, lat=-23.5505, lon=-46.6333))
        db.commit()
    finally:
        db.close()

def log_action(db: Session, device: str, action: str, detail: str = "") -> ActionLog:
    entry = ActionLog(device=device, action=action, detail=detail)
    db.add(entry)
    db.commit()
    db.refresh(entry)
    return entry

def touch_device(db: Session, device_id: str, status: str | None = None) -> Device | None:
    device = db.query(Device).filter(Device.device_id == device_id).first()
    if not device:
        return None
    device.last_seen = datetime.utcnow()
    if status is not None:
        device.status = status
    db.commit()
    return device

// ===== energy.py =====
"""
Modelo energético veicular (documentado).

Potências nominais (W) — ordem de grandeza para bancada:
  P_motor(rpm) ≈ P0 + k_rpm * rpm
  P_farol, P_som, P_ac, P_track constantes

ΔE_bat (Wh) ≈ -Σ P_i * Δt_h
Δfuel (%) ≈ -α * P_motor * Δt_h   (proxy térmico)

Bateria: capacidade nominal C_bat = 12 V · 60 Ah ≈ 720 Wh (escala lab)
"""

from __future__ import annotations
from dataclasses import dataclass
from typing import Any

# Constantes documentadas (lab-scale)
P_HEADLIGHT_W = 120.0
P_SOUND_W = 80.0
P_CLIMATE_W = 150.0
P_TRACK_W = 15.0
P_SPOILER_W = 25.0
P0_ENGINE_W = 200.0
K_RPM = 0.08  # W/rpm proxy
BATTERY_CAPACITY_WH = 720.0
FUEL_ALPHA = 0.00012  # % fuel per W·h


@dataclass
class EnergySnapshot:
    power_w: float
    battery_pct: float
    fuel_pct: float
    components: dict[str, float]

    def to_dict(self) -> dict[str, Any]:
        return {
            "power_w": round(self.power_w, 2),
            "battery_pct": round(self.battery_pct, 2),
            "fuel_pct": round(self.fuel_pct, 2),
            "components_w": {k: round(v, 2) for k, v in self.components.items()},
            "equations": {
                "P_total": "P_motor(rpm)+P_hl+P_sound+P_ac+P_track+P_spoiler",
                "P_motor": "P0 + k_rpm * rpm",
                "dE_bat": "-P_total * dt_hours",
                "dfuel": "-alpha * P_motor * dt_hours",
            },
        }


class EnergyModel:
    def compute(self, actuators: dict, sensors: dict, dt_s: float) -> EnergySnapshot:
        comps: dict[str, float] = {}
        rpm = float(sensors.get("rpm") or 0)
        if actuators.get("engine"):
            comps["motor"] = P0_ENGINE_W + K_RPM * rpm
            if actuators.get("sport_mode"):
                comps["motor"] *= 1.35
        else:
            comps["motor"] = 0.0
        comps["headlight"] = P_HEADLIGHT_W if actuators.get("headlight") else 0.0
        comps["sound"] = P_SOUND_W if actuators.get("sound") else 0.0
        comps["climate"] = P_CLIMATE_W if actuators.get("climate") else 0.0
        comps["track"] = P_TRACK_W if actuators.get("tracking") else 0.0
        comps["spoiler"] = P_SPOILER_W if actuators.get("spoiler") else 0.0
        total = sum(comps.values())
        dt_h = max(0.0, dt_s) / 3600.0
        bat = float(sensors.get("battery") or 100)
        fuel = float(sensors.get("fuel") or 100)
        # battery % from Wh
        d_wh = total * dt_h
        bat = max(5.0, bat - 100.0 * d_wh / BATTERY_CAPACITY_WH)
        fuel = max(1.0, fuel - FUEL_ALPHA * comps["motor"] * dt_h * 1000)
        return EnergySnapshot(power_w=total, battery_pct=bat, fuel_pct=fuel, components=comps)


energy_model = EnergyModel()

