// ===== state.py =====
"""Estado vivo da Ferrari + placas Arduino/Raspberry."""

from __future__ import annotations
import asyncio, time
from copy import deepcopy
from datetime import datetime, timezone
from typing import Any, Callable, Coroutine
from protocol import PROTOCOL_VERSION
from telemetry import telemetry
from statemachine import digital_twin
from security import audit_chain, sign_payload
from energy import energy_model
from hil import hil

BroadcastFn = Callable[[dict[str, Any]], Coroutine[Any, Any, None]]

def _utc() -> str:
    return datetime.now(timezone.utc).isoformat()

class FerrariState:
    def __init__(self) -> None:
        self.sensors = {
            "rpm": 800.0, "speed_kmh": 0.0, "engine_temp": 78.0,
            "battery": 92.0, "fuel": 68.0, "lat": -23.5505, "lon": -46.6333, "power_w": 0.0,
        }
        self.actuators = {
            "door": {"driver": False, "passenger": False}, "roof": False, "engine": False,
            "sound": False, "headlight": False, "tracking": False, "alarm": True,
            "spoiler": False, "climate": False, "horn": False, "sport_mode": False,
            "lock": True, "brake_light": False, "ignition": False,
        }
        self.boards = {
            "arduino": {"id": "arduino-ferrari", "name": "Arduino Ferrari", "online": True, "sync": True,
                        "last_heartbeat": _utc(), "role": "atuação veicular + sensores", "layer": "L1"},
            "raspberry": {"id": "raspberry-hub", "name": "Raspberry Pi Hub", "online": True, "sync": True,
                          "last_heartbeat": _utc(), "role": "coordenação edge + tracking", "layer": "L3"},
        }
        self.sync_pulse = 0
        self.state_version = 0
        self.last_event = "Ferrari Lab iniciado"
        self.energy = energy_model.compute(self.actuators, self.sensors, 0).to_dict()
        self._listeners: list[BroadcastFn] = []
        self._lock = asyncio.Lock()
        self._last_energy_ts = time.perf_counter()
        digital_twin.bind(self.actuators, self.sensors)

    def snapshot(self) -> dict[str, Any]:
        digital_twin.bind(self.actuators, self.sensors)
        return {
            "protocol_version": PROTOCOL_VERSION,
            "state_version": self.state_version,
            "sensors": deepcopy(self.sensors),
            "actuators": deepcopy(self.actuators),
            "boards": deepcopy(self.boards),
            "sync_pulse": self.sync_pulse,
            "last_event": self.last_event,
            "sync_quality_index": telemetry.sync_quality_index(),
            "pair_skew_ms": telemetry.last_sync_pair_ms,
            "twin": digital_twin.ctx.snapshot(),
            "energy": self.energy,
            "hil": hil.snapshot(),
            "audit_tip": audit_chain.tip(),
            "timestamp": _utc(),
        }

    def add_listener(self, fn: BroadcastFn) -> None:
        self._listeners.append(fn)

    def remove_listener(self, fn: BroadcastFn) -> None:
        if fn in self._listeners:
            self._listeners.remove(fn)

    async def broadcast(self, event: str | None = None) -> None:
        if event:
            self.last_event = event
        payload = {"type": "state", "data": self.snapshot()}
        dead = []
        for listener in list(self._listeners):
            try:
                await listener(payload)
            except Exception:
                dead.append(listener)
        for listener in dead:
            self.remove_listener(listener)

    def _bump(self, action: str) -> None:
        now = _utc()
        self.boards["arduino"]["last_heartbeat"] = now
        self.boards["raspberry"]["last_heartbeat"] = now
        self.boards["arduino"]["sync"] = True
        self.boards["raspberry"]["sync"] = True
        self.sync_pulse = (self.sync_pulse + 1) % 1000
        self.state_version += 1
        self.last_event = action
        audit_chain.append(action, sign_payload({"action": action, "v": self.state_version}))

    def _tick_energy(self) -> None:
        now = time.perf_counter()
        dt = now - self._last_energy_ts
        self._last_energy_ts = now
        snap = energy_model.compute(self.actuators, self.sensors, dt)
        self.sensors["battery"] = snap.battery_pct
        self.sensors["fuel"] = snap.fuel_pct
        self.sensors["power_w"] = snap.power_w
        self.energy = snap.to_dict()

    async def _timed(self, name: str, params: dict, mutate) -> dict[str, Any]:
        async def _run():
            t0 = time.perf_counter()
            async with self._lock:
                digital_twin.bind(self.actuators, self.sensors)
                digital_twin.guard(name, params)
                mutate()
                self._tick_energy()
                digital_twin.bind(self.actuators, self.sensors)
                telemetry.record_command(name, (time.perf_counter() - t0) * 1000.0)
                await self.broadcast(self.last_event)
                return self.snapshot()

        delivered, result = await hil.apply(name, _run)
        if not delivered:
            raise ValueError(f"HIL drop: comando '{name}' perdido (loss_rate={hil.config.loss_rate})")
        return result

    async def set_door(self, which: str, open_: bool) -> dict[str, Any]:
        def m():
            if which not in self.actuators["door"]:
                raise ValueError(f"Porta inválida: {which}")
            if self.actuators["lock"] and open_:
                self.actuators["lock"] = False
            self.actuators["door"][which] = open_
            self._bump(f"DOOR {which}={'OPEN' if open_ else 'CLOSE'}")
        return await self._timed("door", {"open": open_, "door_id": which}, m)

    async def set_roof(self, open_: bool) -> dict[str, Any]:
        def m():
            self.actuators["roof"] = open_
            self._bump(f"ROOF={'OPEN' if open_ else 'CLOSE'}")
        return await self._timed("roof", {"open": open_}, m)

    async def set_engine(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["engine"] = on
            self.actuators["ignition"] = on
            if on:
                self.actuators["alarm"] = False
                self.sensors["rpm"] = 1200.0
            else:
                self.sensors["rpm"] = 0.0
                self.sensors["speed_kmh"] = 0.0
                self.actuators["sport_mode"] = False
            self._bump(f"ENGINE={'ON' if on else 'OFF'}")
        return await self._timed("engine", {"on": on}, m)

    async def set_sound(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["sound"] = on
            self._bump(f"SOUND={'ON' if on else 'OFF'}")
        return await self._timed("sound", {"on": on}, m)

    async def set_headlight(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["headlight"] = on
            self._bump(f"HEADLIGHT={'ON' if on else 'OFF'}")
        return await self._timed("headlight", {"on": on}, m)

    async def set_tracking(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["tracking"] = on
            self._bump(f"TRACK={'ON' if on else 'OFF'}")
        return await self._timed("track", {"on": on}, m)

    async def set_alarm(self, armed: bool) -> dict[str, Any]:
        def m():
            self.actuators["alarm"] = armed
            if armed:
                self.actuators["engine"] = False
                self.actuators["ignition"] = False
                self.actuators["lock"] = True
                self.actuators["door"]["driver"] = False
                self.actuators["door"]["passenger"] = False
            self._bump(f"ALARM={'ARMED' if armed else 'DISARMED'}")
        return await self._timed("alarm", {"on": armed}, m)

    async def set_spoiler(self, deployed: bool) -> dict[str, Any]:
        def m():
            self.actuators["spoiler"] = deployed
            self._bump(f"SPOILER={'OUT' if deployed else 'IN'}")
        return await self._timed("spoiler", {"on": deployed}, m)

    async def set_climate(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["climate"] = on
            self._bump(f"CLIMATE={'ON' if on else 'OFF'}")
        return await self._timed("climate", {"on": on}, m)

    async def set_horn(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["horn"] = on
            self._bump(f"HORN={'ON' if on else 'OFF'}")
        snap = await self._timed("horn", {"on": on}, m)
        if on:
            async def _auto_off() -> None:
                await asyncio.sleep(0.45)
                def off():
                    if self.actuators.get("horn"):
                        self.actuators["horn"] = False
                        self._bump("HORN=OFF")
                async with self._lock:
                    off()
                    await self.broadcast(self.last_event)
            asyncio.create_task(_auto_off())
        return snap

    async def set_sport_mode(self, on: bool) -> dict[str, Any]:
        def m():
            self.actuators["sport_mode"] = on
            if on:
                self.actuators["spoiler"] = True
            self._bump(f"SPORT={'ON' if on else 'OFF'}")
        return await self._timed("sport", {"on": on}, m)

    async def set_lock(self, locked: bool) -> dict[str, Any]:
        def m():
            self.actuators["lock"] = locked
            if locked:
                self.actuators["door"]["driver"] = False
                self.actuators["door"]["passenger"] = False
            self._bump(f"LOCK={'ON' if locked else 'OFF'}")
        return await self._timed("lock", {"on": locked}, m)

    async def update_sensors(self, **kwargs: Any) -> dict[str, Any]:
        async with self._lock:
            for k, v in kwargs.items():
                if k in self.sensors:
                    self.sensors[k] = v
            self._tick_energy()
            if self.actuators["tracking"]:
                telemetry.record_track(self.sensors["lat"], self.sensors["lon"])
            self.state_version += 1
            await self.broadcast("Telemetria atualizada")
            return self.snapshot()

    async def heartbeat(self, board: str) -> dict[str, Any]:
        async with self._lock:
            if board not in self.boards:
                raise ValueError(f"Placa inválida: {board}")
            self.boards[board]["online"] = True
            self.boards[board]["last_heartbeat"] = _utc()
            sample = telemetry.record_heartbeat(board)
            synced = bool(sample.get("synced"))
            self.boards["arduino"]["sync"] = synced
            self.boards["raspberry"]["sync"] = synced
            self.sync_pulse = (self.sync_pulse + 1) % 1000
            self.state_version += 1
            await self.broadcast(f"Heartbeat {board}")
            return self.snapshot()

ferrari_state = FerrariState()

// ===== statemachine.py =====
"""
Gêmeo digital formal — máquina de estados / statechart com invariantes.

Modos: SECURE → IDLE → READY → RUNNING → SPORT
Eventos inválidos levantam InvariantViolation (rejeição segura).
"""

from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Any


class Mode(str, Enum):
    SECURE = "SECURE"
    IDLE = "IDLE"
    READY = "READY"
    RUNNING = "RUNNING"
    SPORT = "SPORT"


class InvariantViolation(Exception):
    def __init__(self, code: str, message: str):
        self.code = code
        super().__init__(message)


@dataclass
class TwinContext:
    actuators: dict[str, Any]
    sensors: dict[str, Any]
    mode: Mode = Mode.SECURE
    last_rejected: list[dict[str, str]] = field(default_factory=list)

    def snapshot(self) -> dict[str, Any]:
        return {
            "mode": self.mode.value,
            "invariants": INVARIANT_CATALOG,
            "transitions": TRANSITION_TABLE,
            "last_rejected": self.last_rejected[-10:],
        }


INVARIANT_CATALOG = [
    {"id": "INV-01", "rule": "Não abrir porta se sport_mode AND speed_kmh > 0"},
    {"id": "INV-02", "rule": "Não ligar motor se alarm armado"},
    {"id": "INV-03", "rule": "Não entrar em SPORT sem engine ON"},
    {"id": "INV-04", "rule": "Não abrir teto se speed_kmh > 40"},
    {"id": "INV-05", "rule": "Travar implica fechar portas"},
    {"id": "INV-06", "rule": "SECURE exige engine OFF e lock ON"},
]

TRANSITION_TABLE = {
    "SECURE": ["IDLE"],
    "IDLE": ["SECURE", "READY"],
    "READY": ["IDLE", "RUNNING", "SECURE"],
    "RUNNING": ["READY", "SPORT", "IDLE"],
    "SPORT": ["RUNNING", "READY"],
}


class DigitalTwin:
    def __init__(self) -> None:
        self.ctx = TwinContext(actuators={}, sensors={})

    def bind(self, actuators: dict, sensors: dict) -> None:
        self.ctx.actuators = actuators
        self.ctx.sensors = sensors
        self._recompute_mode()

    def _recompute_mode(self) -> None:
        a, s = self.ctx.actuators, self.ctx.sensors
        if a.get("alarm") and a.get("lock") and not a.get("engine"):
            self.ctx.mode = Mode.SECURE
        elif a.get("sport_mode") and a.get("engine"):
            self.ctx.mode = Mode.SPORT
        elif a.get("engine"):
            self.ctx.mode = Mode.RUNNING
        elif not a.get("lock") and not a.get("alarm"):
            self.ctx.mode = Mode.READY if a.get("ignition") or True else Mode.IDLE
            if not a.get("engine") and not a.get("alarm"):
                self.ctx.mode = Mode.READY if not a.get("lock") else Mode.IDLE
        else:
            self.ctx.mode = Mode.IDLE

    def guard(self, action: str, params: dict[str, Any] | None = None) -> None:
        """Valida invariantes antes da mutação. params descreve a intenção."""
        params = params or {}
        a, s = self.ctx.actuators, self.ctx.sensors
        speed = float(s.get("speed_kmh") or 0)

        try:
            if action == "door" and params.get("open"):
                if a.get("sport_mode") and speed > 0:
                    raise InvariantViolation("INV-01", "Porta bloqueada: Sport + velocidade > 0")
                if a.get("lock"):
                    # auto-unlock allowed only if not SECURE with alarm? allow unlock path separately
                    pass
            if action == "engine" and params.get("on") and a.get("alarm"):
                raise InvariantViolation("INV-02", "Motor bloqueado: alarme armado")
            if action == "sport" and params.get("on") and not a.get("engine"):
                raise InvariantViolation("INV-03", "Sport requer motor ligado")
            if action == "roof" and params.get("open") and speed > 40:
                raise InvariantViolation("INV-04", "Teto bloqueado: velocidade > 40 km/h")
            if action == "lock" and params.get("on"):
                # will force doors closed in mutate
                pass
            if action == "alarm" and params.get("on") and a.get("engine"):
                raise InvariantViolation("INV-06", "Não armar alarme com motor ligado")
        except InvariantViolation as exc:
            self.ctx.last_rejected.append({"code": exc.code, "message": str(exc), "action": action})
            raise

        self._recompute_mode()


digital_twin = DigitalTwin()

// ===== telemetry.py =====
"""Telemetria e Sync Quality Index — Ferrari Postdoc Lab."""

from __future__ import annotations
import math, statistics, time
from collections import deque
from dataclasses import dataclass, field
from datetime import datetime, timezone
from typing import Any

def _utc() -> str:
    return datetime.now(timezone.utc).isoformat()

@dataclass
class TelemetryEngine:
    window: int = 240
    command_latencies_ms: deque[float] = field(default_factory=lambda: deque(maxlen=240))
    sync_intervals_ms: deque[float] = field(default_factory=lambda: deque(maxlen=240))
    heartbeats: dict[str, float] = field(default_factory=dict)
    series: deque[dict[str, Any]] = field(default_factory=lambda: deque(maxlen=240))
    total_commands: int = 0
    total_sync_events: int = 0
    desync_events: int = 0
    last_sync_pair_ms: float | None = None
    started_at: float = field(default_factory=time.perf_counter)
    track_points: deque[dict[str, float]] = field(default_factory=lambda: deque(maxlen=120))

    def record_command(self, name: str, latency_ms: float) -> None:
        self.total_commands += 1
        self.command_latencies_ms.append(max(0.0, float(latency_ms)))
        self.series.append({"kind": "command", "name": name, "latency_ms": round(latency_ms, 3), "ts": _utc()})

    def record_heartbeat(self, board: str) -> dict[str, Any]:
        now = time.perf_counter()
        prev = self.heartbeats.get(board)
        self.heartbeats[board] = now
        self.total_sync_events += 1
        if prev is not None:
            self.sync_intervals_ms.append((now - prev) * 1000.0)
        ar, rp = self.heartbeats.get("arduino"), self.heartbeats.get("raspberry")
        pair_ms, synced = None, False
        if ar is not None and rp is not None:
            pair_ms = abs(ar - rp) * 1000.0
            self.last_sync_pair_ms = pair_ms
            synced = pair_ms < 2500.0
            if not synced:
                self.desync_events += 1
        sample = {"ts": _utc(), "board": board, "pair_skew_ms": round(pair_ms, 3) if pair_ms is not None else None, "synced": synced}
        self.series.append({"kind": "heartbeat", **sample})
        return sample

    def record_track(self, lat: float, lon: float) -> None:
        self.track_points.append({"lat": lat, "lon": lon, "t": time.time()})

    def _stats(self, values: deque[float]) -> dict[str, float | None]:
        if not values:
            return {"n": 0, "mean": None, "p50": None, "p95": None, "stdev": None}
        data = sorted(values)
        def pct(p: float) -> float:
            k = (len(data) - 1) * (p / 100.0)
            f, c = math.floor(k), math.ceil(k)
            if f == c:
                return data[int(k)]
            return data[f] * (c - k) + data[c] * (k - f)
        return {
            "n": len(data),
            "mean": round(statistics.fmean(data), 3),
            "p50": round(pct(50), 3),
            "p95": round(pct(95), 3),
            "stdev": round(statistics.pstdev(data), 3) if len(data) > 1 else 0.0,
        }

    def sync_quality_index(self) -> float:
        if self.total_sync_events == 0:
            return 0.0
        skew = self.last_sync_pair_ms
        skew_score = 100.0 if skew is None else max(0.0, 100.0 - min(skew, 5000.0) / 50.0)
        jitter = self._stats(self.sync_intervals_ms)["stdev"] or 0.0
        jitter_score = max(0.0, 100.0 - float(jitter) / 10.0)
        desync_rate = self.desync_events / max(1, self.total_sync_events)
        reliability = max(0.0, 100.0 * (1.0 - min(1.0, desync_rate * 4)))
        return round(0.45 * skew_score + 0.30 * jitter_score + 0.25 * reliability, 2)

    def summary(self) -> dict[str, Any]:
        return {
            "uptime_s": round(time.perf_counter() - self.started_at, 1),
            "protocol_metrics": {
                "total_commands": self.total_commands,
                "total_sync_events": self.total_sync_events,
                "desync_events": self.desync_events,
                "last_pair_skew_ms": round(self.last_sync_pair_ms, 3) if self.last_sync_pair_ms is not None else None,
            },
            "command_latency_ms": self._stats(self.command_latencies_ms),
            "heartbeat_interval_ms": self._stats(self.sync_intervals_ms),
            "sync_quality_index": self.sync_quality_index(),
            "track_points": list(self.track_points)[-40:],
            "series_tail": list(self.series)[-40:],
            "generated_at": _utc(),
        }

