@router.websocket("/ws")
async def websocket_endpoint(websocket: WebSocket):
    await websocket.accept()
    await websocket.send_json({"type": "state", "data": ferrari_state.snapshot()})

    async def forward(payload: dict[str, Any]) -> None:
        await websocket.send_json(payload)

    ferrari_state.add_listener(forward)
    try:
        while True:
            data = await websocket.receive_json()
            action = data.get("action")
            try:
                if action == "door":
                    await ferrari_state.set_door(str(data.get("door_id", "driver")), bool(data.get("open")))
                elif action == "roof":
                    await ferrari_state.set_roof(bool(data.get("on", data.get("open"))))
                elif action == "engine":
                    await ferrari_state.set_engine(bool(data.get("on")))
                elif action == "sound":
                    await ferrari_state.set_sound(bool(data.get("on")))
                elif action == "headlight":
                    await ferrari_state.set_headlight(bool(data.get("on")))
                elif action == "track":
                    await ferrari_state.set_tracking(bool(data.get("on")))
                elif action == "alarm":
                    await ferrari_state.set_alarm(bool(data.get("on")))
                elif action == "spoiler":
                    await ferrari_state.set_spoiler(bool(data.get("on")))
                elif action == "climate":
                    await ferrari_state.set_climate(bool(data.get("on")))
                elif action == "horn":
                    await ferrari_state.set_horn(bool(data.get("on")))
                elif action == "sport":
                    await ferrari_state.set_sport_mode(bool(data.get("on")))
                elif action == "lock":
                    await ferrari_state.set_lock(bool(data.get("on")))
                elif action == "simulate":
                    db = SessionLocal()
                    try:
                        await simulator.run_scenario(str(data.get("scenario", "startup")), db)
                    finally:
                        db.close()
                elif action == "ping":
                    await websocket.send_json({"type": "pong", "ts": datetime.utcnow().isoformat()})
            except InvariantViolation as exc:
                await websocket.send_json({
                    "type": "invariant_violation",
                    "invariant": exc.code,
                    "message": str(exc),
                })
            except ValueError as exc:
                await websocket.send_json({"type": "error", "message": str(exc)})
    except WebSocketDisconnect:
        pass
    finally:
        ferrari_state.remove_listener(forward)

"""
Gêmeo digital formal — máquina de estados / statechart com invariantes.

Modos: SECURE → IDLE → READY → RUNNING → SPORT
Eventos inválidos levantam InvariantViolation (rejeição segura).
"""

from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Any


class Mode(str, Enum):
    SECURE = "SECURE"
    IDLE = "IDLE"
    READY = "READY"
    RUNNING = "RUNNING"
    SPORT = "SPORT"


class InvariantViolation(Exception):
    def __init__(self, code: str, message: str):
        self.code = code
        super().__init__(message)


@dataclass
class TwinContext:
    actuators: dict[str, Any]
    sensors: dict[str, Any]
    mode: Mode = Mode.SECURE
    last_rejected: list[dict[str, str]] = field(default_factory=list)

    def snapshot(self) -> dict[str, Any]:
        return {
            "mode": self.mode.value,
            "invariants": INVARIANT_CATALOG,
            "transitions": TRANSITION_TABLE,
            "last_rejected": self.last_rejected[-10:],
        }


INVARIANT_CATALOG = [
    {"id": "INV-01", "rule": "Não abrir porta se sport_mode AND speed_kmh > 0"},
    {"id": "INV-02", "rule": "Não ligar motor se alarm armado"},
    {"id": "INV-03", "rule": "Não entrar em SPORT sem engine ON"},
    {"id": "INV-04", "rule": "Não abrir teto se speed_kmh > 40"},
    {"id": "INV-05", "rule": "Travar implica fechar portas"},
    {"id": "INV-06", "rule": "SECURE exige engine OFF e lock ON"},
]

TRANSITION_TABLE = {
    "SECURE": ["IDLE"],
    "IDLE": ["SECURE", "READY"],
    "READY": ["IDLE", "RUNNING", "SECURE"],
    "RUNNING": ["READY", "SPORT", "IDLE"],
    "SPORT": ["RUNNING", "READY"],
}


class DigitalTwin:
    def __init__(self) -> None:
        self.ctx = TwinContext(actuators={}, sensors={})

    def bind(self, actuators: dict, sensors: dict) -> None:
        self.ctx.actuators = actuators
        self.ctx.sensors = sensors
        self._recompute_mode()

    def _recompute_mode(self) -> None:
        a, s = self.ctx.actuators, self.ctx.sensors
        if a.get("alarm") and a.get("lock") and not a.get("engine"):
            self.ctx.mode = Mode.SECURE
        elif a.get("sport_mode") and a.get("engine"):
            self.ctx.mode = Mode.SPORT
        elif a.get("engine"):
            self.ctx.mode = Mode.RUNNING
        elif not a.get("lock") and not a.get("alarm"):
            self.ctx.mode = Mode.READY if a.get("ignition") or True else Mode.IDLE
            if not a.get("engine") and not a.get("alarm"):
                self.ctx.mode = Mode.READY if not a.get("lock") else Mode.IDLE
        else:
            self.ctx.mode = Mode.IDLE

    def guard(self, action: str, params: dict[str, Any] | None = None) -> None:
        """Valida invariantes antes da mutação. params descreve a intenção."""
        params = params or {}
        a, s = self.ctx.actuators, self.ctx.sensors
        speed = float(s.get("speed_kmh") or 0)

        try:
            if action == "door" and params.get("open"):
                if a.get("sport_mode") and speed > 0:
                    raise InvariantViolation("INV-01", "Porta bloqueada: Sport + velocidade > 0")
                if a.get("lock"):
                    # auto-unlock allowed only if not SECURE with alarm? allow unlock path separately
                    pass
            if action == "engine" and params.get("on") and a.get("alarm"):
                raise InvariantViolation("INV-02", "Motor bloqueado: alarme armado")
            if action == "sport" and params.get("on") and not a.get("engine"):
                raise InvariantViolation("INV-03", "Sport requer motor ligado")
            if action == "roof" and params.get("open") and speed > 40:
                raise InvariantViolation("INV-04", "Teto bloqueado: velocidade > 40 km/h")
            if action == "lock" and params.get("on"):
                # will force doors closed in mutate
                pass
            if action == "alarm" and params.get("on") and a.get("engine"):
                raise InvariantViolation("INV-06", "Não armar alarme com motor ligado")
        except InvariantViolation as exc:
            self.ctx.last_rejected.append({"code": exc.code, "message": str(exc), "action": action})
            raise

        self._recompute_mode()


digital_twin = DigitalTwin()

"""
Integridade criptográfica: HMAC-SHA256 nos comandos + cadeia hash de auditoria.
"""

from __future__ import annotations
import hashlib
import hmac
import json
import os
import time
from dataclasses import dataclass, field
from typing import Any

SECRET = os.getenv("FERRARI_HMAC_SECRET", "ferrari-postdoc-hmac-secret-v1").encode("utf-8")


def sign_payload(payload: dict[str, Any]) -> dict[str, Any]:
    body = json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")
    sig = hmac.new(SECRET, body, hashlib.sha256).hexdigest()
    return {**payload, "hmac": sig, "signed_at": time.time()}


def verify_payload(payload: dict[str, Any]) -> bool:
    if "hmac" not in payload:
        return False
    copy = {k: v for k, v in payload.items() if k not in ("hmac",)}
    # signed_at is part of signed material when present after sign — verify against fields except hmac
    expected = sign_payload({k: v for k, v in copy.items() if k != "signed_at"})
    # Re-sign without signed_at drift: compare hmac of canonical without hmac/signed_at
    body = json.dumps({k: v for k, v in payload.items() if k not in ("hmac", "signed_at")}, sort_keys=True, separators=(",", ":")).encode("utf-8")
    sig = hmac.new(SECRET, body, hashlib.sha256).hexdigest()
    return hmac.compare_digest(sig, payload["hmac"])


@dataclass
class AuditChain:
    entries: list[dict[str, Any]] = field(default_factory=list)
    genesis: str = field(default_factory=lambda: hashlib.sha256(b"ferrari-genesis").hexdigest())

    def append(self, event: str, detail: dict[str, Any] | None = None) -> dict[str, Any]:
        prev = self.entries[-1]["hash"] if self.entries else self.genesis
        record = {
            "seq": len(self.entries) + 1,
            "ts": time.time(),
            "event": event,
            "detail": detail or {},
            "prev_hash": prev,
        }
        blob = json.dumps(record, sort_keys=True, separators=(",", ":")).encode("utf-8")
        record["hash"] = hashlib.sha256(blob).hexdigest()
        signed = sign_payload({"seq": record["seq"], "event": event, "hash": record["hash"], "prev_hash": prev})
        record["hmac"] = signed["hmac"]
        self.entries.append(record)
        return record

    def verify_chain(self) -> dict[str, Any]:
        prev = self.genesis
        for i, e in enumerate(self.entries):
            if e["prev_hash"] != prev:
                return {"ok": False, "broken_at": i, "reason": "prev_hash mismatch"}
            check = {k: v for k, v in e.items() if k not in ("hash", "hmac")}
            blob = json.dumps(check, sort_keys=True, separators=(",", ":")).encode("utf-8")
            if hashlib.sha256(blob).hexdigest() != e["hash"]:
                return {"ok": False, "broken_at": i, "reason": "hash mismatch"}
            prev = e["hash"]
        return {"ok": True, "length": len(self.entries), "tip": prev if self.entries else self.genesis}

    def tip(self) -> str:
        return self.entries[-1]["hash"] if self.entries else self.genesis


audit_chain = AuditChain()
audit_chain.append("BOOT", {"app": "Ferrari IoT Postdoc"})

