  font-family: var(--font-mono);
  letter-spacing: 0.18em;
}
.tiny { fill: #7a756e; font-size: 10px; font-family: var(--font-mono); }

/* Butterfly doors + actuators */
.door-panel {
  transform-origin: 8px 50px;
  transition: transform 0.95s cubic-bezier(0.34, 1.3, 0.64, 1);
}
.door-panel.open {
  transform: rotate(-68deg) translate(-12px, -42px);
}
.door-panel.passenger {
  transform-origin: 10px 40px;
}
.door-panel.passenger.open {
  transform: rotate(64deg) translate(18px, -48px);
}
.roof-panel {
  transform-origin: 520px 170px;
  transition: transform 0.9s var(--ease), opacity 0.55s;
}
.roof-panel.open {
  transform: translateY(-48px) rotate(-8deg) scale(0.9);
  opacity: 0.2;
}
.spoiler {
  transform: translate(730px, 258px) scaleY(0.85);
  transition: transform 0.75s cubic-bezier(0.22, 1, 0.36, 1);
  opacity: 0.85;
}
.spoiler.out {
  transform: translate(730px, 205px) scaleY(1);
}
.spoiler.out .spoiler-tag { opacity: 1; }
.wheel .rim-spokes {
  transform-origin: 0px 0px;
  transform-box: view-box;
}
#car.engine-on .wheel .rim-spokes {
  animation: spin 0.4s linear infinite;
}
#car.engine-on #body { filter: brightness(1.06) saturate(1.06) url(#softShadow); }
#car.engine-on #exhaust { opacity: 0.85 !important; }

/* Sport — sem piscar; badge + underglow estável */
#car.sport-on #body { filter: brightness(1.1) saturate(1.2); }
.sport-fx { transition: opacity 0.35s ease; pointer-events: none; }
#car.sport-on .sport-fx { opacity: 1; }

/* A/C */
.climate-fx { transition: opacity 0.35s ease; }
#car.climate-on .climate-fx { opacity: 1; }
#car.climate-on .ac-flow {
  stroke-dasharray: 8 6;
  animation: acWave 1.1s ease-in-out infinite;
}
#car.climate-on .ac-flow.d2 { animation-delay: 0.15s; }
#car.climate-on .ac-flow.d3 { animation-delay: 0.3s; }
#car.climate-on .ac-dot { animation: acFloat 1.4s ease-in-out infinite; }
#car.climate-on .ac-dot.d2 { animation-delay: 0.2s; }
#car.climate-on .ac-dot.d3 { animation-delay: 0.4s; }

/* Horn */
.horn-blast { transition: opacity 0.1s; }
#car.horn-blast .horn-blast,
.horn-blast.active {
  opacity: 1;
  animation: hornRing 0.55s ease-out;
}
#car.horn-blast .horn-blast ellipse:nth-child(2) { animation-delay: 0.05s; }
#car.horn-blast .horn-blast ellipse:nth-child(3) { animation-delay: 0.1s; }

/* Lock */
.lock-fx { transition: opacity 0.35s ease, transform 0.45s var(--ease); }
#car.locked .lock-fx { opacity: 1; }
#car.locked .door-panel { filter: brightness(0.85); }

/* Alarm — indicador estático (sem strobe/pisca) */
.alarm-fx { transition: opacity 0.25s ease; }
#car.alarm-on .alarm-fx { opacity: 1; }
#car.alarm-on .alarm-strobe { opacity: 0.12; }
#car.alarm-on .alarm-beacon { opacity: 0.85; }

@keyframes spin { to { transform: rotate(360deg); } }
@keyframes acWave {
  0%, 100% { opacity: 0.35; stroke-dashoffset: 0; }
  50% { opacity: 1; stroke-dashoffset: -12; }
}
@keyframes acFloat {
  0% { transform: translate(0, 0); opacity: 0.3; }
  50% { transform: translate(12px, -14px); opacity: 1; }
  100% { transform: translate(24px, -8px); opacity: 0.2; }
}
@keyframes hornRing {
  0% { opacity: 0.95; transform: scale(0.6); }
  100% { opacity: 0; transform: scale(1.35); }
}
@keyframes tagPulse {
  0%, 100% { opacity: 0.55; }
  50% { opacity: 1; }
}

